import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"妖精","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/妖精.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/妖精.md"}'),d={name:"4.资源分区/1.血统与训练/6.一次性血统/妖精.md"};function l(i,a,_,b,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"妖精",tabindex:"-1"},[s("妖精 "),e("a",{class:"header-anchor",href:"#妖精","aria-label":'Permalink to "妖精"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌032")])])],-1),o('<h1 id="妖精-1" tabindex="-1">妖精 <a class="header-anchor" href="#妖精-1" aria-label="Permalink to &quot;妖精&quot;">​</a></h1><p>妖精<br> 魔幻本质<br> 一次性血统<br> D+600<br> 描述：这些小型而欢快的生命由自然中最纯粹的魔法微粒组成，他们通常有着一头金色或粉色的长发，背生两对透明的膜翅，飞行时微微发光，并且在身后留下星星点点的拖尾。<br> 特性：【幻巧之躯】【自然戏法】<br> 【幻巧之躯】：妖精们都是小型的生命，购买该血统后，体积降低为1。从自然的魔力之中孕育，所有的妖精都拥有天然的魔力，你开启精神魔力池，关键属性为智力+感知，恢复方式和基础用法与精神魔力相同。<br> 妖精一族只要魔力池不为空就可以进行飞行，机动性为普通，飞行时，妖精的身躯会微微发光。同时，这些小妖精只需要魔力就可以维持生命，只要魔力池不为空，妖精就无需饮食，也不需要休息。<br> 【自然戏法】：妖精们拥有新的精神魔力用法：<br> 结合在一次移动中，消耗1点魔力，这次移动的移速额外提升10米。<br> 每轮第一次承受攻击时，消耗1点魔力，针对这次攻击获得1点闪避防御。<br> 结合在一次智力属性相关检定中，消耗2点魔力，这次检定获得1点附加成功。<br> 当内在最高等级至少为C级时，可以消耗3点精神魔力获得持续一轮的1点快速医疗（12点医疗池），也可以将该快速医疗给予任意一个触及到的友方，而不对自己生效。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
